<template><div><el-card><div class="toolbar"><h2>套餐管理</h2><el-input v-model="q.keyword" placeholder="关键字" style="width:200px"/><el-button type="primary" @click="load">查询</el-button><el-button type="success" @click="open({})">新增</el-button></div><el-table :data="list"><el-table-column prop="routeId" label="线路ID"/><el-table-column prop="packageName" label="套餐名"/><el-table-column prop="packageType" label="类型"/><el-table-column prop="price" label="价格"/><el-table-column label="状态"><template #default="{row}"><StatusTag :value="row.status"/></template></el-table-column><el-table-column label="操作" width="220"><template #default="{row}"><el-button link @click="open(row)">编辑</el-button><el-button link type="danger" @click="del(row.id)">删除</el-button></template></el-table-column></el-table></el-card><el-dialog v-model="show" title="套餐管理"><el-form :model="form" label-width="100px"><el-form-item label="线路ID"><el-input-number v-model="form.routeId"/></el-form-item><el-form-item label="套餐名"><el-input v-model="form.packageName"/></el-form-item><el-form-item label="类型"><el-input v-model="form.packageType"/></el-form-item><el-form-item label="价格"><el-input-number v-model="form.price"/></el-form-item><el-form-item label="包含服务"><el-input type="textarea" v-model="form.includeService"/></el-form-item><el-form-item label="不含服务"><el-input type="textarea" v-model="form.excludeService"/></el-form-item><el-form-item label="状态"><el-select v-model="form.status"><el-option label="启用" value="ENABLE"/><el-option label="停用" value="DISABLE"/></el-select></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue'; import { ElMessage,ElMessageBox } from 'element-plus'; import { packageApi } from '../../api/modules'; import StatusTag from '../../components/StatusTag.vue'; const q=reactive({page:1,size:20}),list=ref([]),show=ref(false),form=reactive({}); async function load(){const d=await packageApi.list(q); list.value=d.records||d} function open(row){Object.keys(form).forEach(k=>delete form[k]); Object.assign(form,row); show.value=true} async function save(){form.id?await packageApi.update(form.id,form):await packageApi.add(form); ElMessage.success('保存成功'); show.value=false; load()} async function del(id){await ElMessageBox.confirm('确认删除？'); await packageApi.del(id); load()} onMounted(load)</script>
